const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const savedArticles = JSON.parse(localStorage.getItem('saved_articles') || '[]');

// Determine 12-month window based on current date
const now = new Date();
const cutoff = new Date(now);
cutoff.setMonth(cutoff.getMonth() - 12);

// All qualifying budget articles (category, budget, date)
const qualifyingArticles = articles.filter(a => {
  if (!a || a.category_id !== 'budget_money') return false;
  if (typeof a.overall_budget_max !== 'number' || a.overall_budget_max > 10000) return false;
  if (!a.published_at) return false;
  const d = new Date(a.published_at);
  if (isNaN(d.getTime())) return false;
  return d >= cutoff && d <= now;
});

// Rank qualifying articles by popularity
const sortedQualifying = qualifyingArticles.slice().sort((a, b) => {
  const ap = typeof a.popularity_score === 'number' ? a.popularity_score : 0;
  const bp = typeof b.popularity_score === 'number' ? b.popularity_score : 0;
  return bp - ap;
});
const topN = 3;
const topArticles = sortedQualifying.slice(0, topN);
const topIds = topArticles.map(a => a.id);

// Saved articles that meet the budget + date + category criteria
const qualifyingSaved = savedArticles.filter(sa => {
  const art = articles.find(a => a.id === sa.article_id);
  if (!art) return false;
  if (art.category_id !== 'budget_money') return false;
  if (typeof art.overall_budget_max !== 'number' || art.overall_budget_max > 10000) return false;
  if (!art.published_at) return false;
  const d = new Date(art.published_at);
  if (isNaN(d.getTime())) return false;
  if (d < cutoff || d > now) return false;
  return true;
});

// CP1-3 (0.20 each): At least 1, 2, 3 qualifying budget articles saved
[1, 2, 3].forEach(n => {
  checkpoints.push({
    passed: qualifyingSaved.length >= n,
    weight: 0.2
  });
});

// CP4 (0.40): At least 3 of the saved qualifying articles are among the top 3 most popular qualifying ones
const popularQualifyingSaved = qualifyingSaved.filter(sa => topIds.includes(sa.article_id));
checkpoints.push({
  passed: popularQualifyingSaved.length >= 3,
  weight: 0.4
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const templates = JSON.parse(localStorage.getItem('timeline_templates') || '[]');
const boardItems = JSON.parse(localStorage.getItem('planning_board_items') || '[]');

// Find qualifying timeline templates
const qualifyingTemplates = templates.filter(t => {
  if (!t) return false;
  if (t.season !== 'summer') return false;
  if (t.location_type !== 'outdoor_ceremony_reception') return false;
  if (t.length_hours !== 8) return false;
  if (t.ceremony_time !== '4:00 PM') return false;
  if (typeof t.guest_count_min !== 'number' || typeof t.guest_count_max !== 'number') return false;
  // Require the template's range to cover 50–150 guests
  return t.guest_count_min <= 50 && t.guest_count_max >= 150;
});

// Planning board items that save one of these templates
const qualifyingSavedItems = boardItems.filter(item => {
  if (!item || item.item_type !== 'timeline_template') return false;
  return qualifyingTemplates.some(t => t.id === item.item_id);
});

// Single checkpoint: at least one qualifying timeline template saved
checkpoints.push({
  passed: qualifyingSavedItems.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const palettes = JSON.parse(localStorage.getItem('color_palettes') || '[]');
const moodboards = JSON.parse(localStorage.getItem('moodboards') || '[]');

// IDs of palettes that match the tag and palette_type criteria
const qualifyingPaletteIds = palettes
  .filter(p => {
    if (!p) return false;
    if (p.palette_type !== 'includes_neutrals') return false;
    const tags = Array.isArray(p.tags) ? p.tags : [];
    return tags.includes('Sage Green') && tags.includes('Gold');
  })
  .map(p => p.id);

// For each moodboard, count how many qualifying palettes it contains
let maxQualifyingOnBoard = 0;
(moodboards || []).forEach(mb => {
  if (!mb || !Array.isArray(mb.palette_ids)) return;
  const count = mb.palette_ids.filter(id => qualifyingPaletteIds.includes(id)).length;
  if (count > maxQualifyingOnBoard) maxQualifyingOnBoard = count;
});

// CP1-4 (0.25 each): At least 1, 2, 3, 4 qualifying palettes on the same moodboard
[1, 2, 3, 4].forEach(n => {
  checkpoints.push({
    passed: maxQualifyingOnBoard >= n,
    weight: 0.25
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const savedArticles = JSON.parse(localStorage.getItem('saved_articles') || '[]');

// Qualifying venue guides
const qualifyingVenueArticles = articles.filter(a => {
  if (!a) return false;
  if (a.category_id !== 'venues') return false;
  if (!a.has_backup_indoor_space) return false;
  const tags = Array.isArray(a.venue_style_tags) ? a.venue_style_tags : [];
  const hasStyle = tags.includes('barn') || tags.includes('hotel_ballroom');
  if (!hasStyle) return false;
  // Approximate "around 150 guests" as overlapping 120–180
  if (typeof a.guest_count_min !== 'number' || typeof a.guest_count_max !== 'number') return false;
  const rangeMin = 120;
  const rangeMax = 180;
  return a.guest_count_max >= rangeMin && a.guest_count_min <= rangeMax;
});

// Saved articles that are in the qualifying set
const qualifyingSaved = savedArticles.filter(sa => qualifyingVenueArticles.some(a => a.id === sa.article_id));

// Single checkpoint: at least one qualifying venue guide saved
checkpoints.push({
  passed: qualifyingSaved.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const layouts = JSON.parse(localStorage.getItem('seating_layouts') || '[]');
const boardItems = JSON.parse(localStorage.getItem('planning_board_items') || '[]');

// Qualifying seating layouts
const qualifyingLayouts = layouts.filter(l => {
  if (!l) return false;
  if (typeof l.guest_count_min !== 'number' || typeof l.guest_count_max !== 'number') return false;
  // Specifically intended for the 100–150 guest range
  if (l.guest_count_min < 100 || l.guest_count_max > 150) return false;
  if (!l.is_mixed_tables) return false;
  const opts = Array.isArray(l.layout_type_options) ? l.layout_type_options : [];
  return opts.includes('round_tables') && opts.includes('long_tables');
});

// Planning board items that save one of these layouts
const qualifyingSaved = boardItems.filter(item => {
  if (!item || item.item_type !== 'seating_layout') return false;
  return qualifyingLayouts.some(l => l.id === item.item_id);
});

// Single checkpoint: at least one qualifying seating layout saved
checkpoints.push({
  passed: qualifyingSaved.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const templates = JSON.parse(localStorage.getItem('checklist_templates') || '[]');
const taskTemplates = JSON.parse(localStorage.getItem('checklist_task_templates') || '[]');
const todos = JSON.parse(localStorage.getItem('todos') || '[]');

// Identify appropriate checklist template(s): 6 months, budget under 15k, 80–120 guests
const targetTemplates = templates.filter(t => {
  if (!t) return false;
  if (t.timeline_months !== 6) return false;
  // Budget under 15k
  if (typeof t.budget_max === 'number' && t.budget_max > 15000) return false;
  if (typeof t.budget_min === 'number' && t.budget_min > 15000) return false;
  // Guest count range overlaps 80–120
  if (typeof t.guest_count_min === 'number' && t.guest_count_min > 120) return false;
  if (typeof t.guest_count_max === 'number' && t.guest_count_max < 80) return false;
  return true;
});

let matchingTodosCount = 0;
if (targetTemplates.length > 0) {
  const template = targetTemplates[0];
  const thisMonthTasks = taskTemplates
    .filter(ct => ct.checklist_template_id === template.id && ct.section_name === 'This Month')
    .sort((a, b) => {
      const ao = typeof a.order === 'number' ? a.order : 0;
      const bo = typeof b.order === 'number' ? b.order : 0;
      return ao - bo;
    });

  const firstFive = thisMonthTasks.slice(0, 5);
  const firstFiveIds = firstFive.map(t => t.id);

  const matchingTodos = todos.filter(td => td.source_type === 'checklist_task' && firstFiveIds.includes(td.source_id));
  matchingTodosCount = matchingTodos.length;
}

// CP1-5 (0.20 each): At least 1,2,3,4,5 of the specific first-five tasks added as todos
[1, 2, 3, 4, 5].forEach(n => {
  checkpoints.push({
    passed: matchingTodosCount >= n,
    weight: 0.2
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const articles = JSON.parse(localStorage.getItem('articles') || '[]');
const links = JSON.parse(localStorage.getItem('budget_article_links') || '[]');

// Links under Catering whose articles meet the criteria
const qualifyingLinks = links.filter(link => {
  if (!link || link.category_slug !== 'catering') return false;
  const art = articles.find(a => a.id === link.article_id);
  if (!art) return false;
  if (art.category_id !== 'food_drink') return false;
  if (!art.is_budget_breakdown) return false;
  if (typeof art.average_catering_cost_per_guest !== 'number') return false;
  if (art.average_catering_cost_per_guest > 60) return false;

  // If per-guest budget range is specified, ensure it intersects $40–$60
  const min = typeof art.budget_per_guest_min === 'number' ? art.budget_per_guest_min : null;
  const max = typeof art.budget_per_guest_max === 'number' ? art.budget_per_guest_max : null;
  if (min !== null && max !== null) {
    if (max < 40 || min > 60) return false;
  }
  return true;
});

// Single checkpoint: at least one qualifying catering article linked
checkpoints.push({
  passed: qualifyingLinks.length >= 1,
  weight: 1.0
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const projects = JSON.parse(localStorage.getItem('diy_projects') || '[]');
const saved = JSON.parse(localStorage.getItem('saved_projects') || '[]');

// IDs of projects that meet time, cost, and difficulty requirements
const qualifyingProjectIds = projects
  .filter(p => {
    if (!p) return false;
    if (p.difficulty !== 'beginner') return false;
    if (typeof p.time_required_minutes !== 'number' || p.time_required_minutes > 120) return false;
    if (typeof p.cost_estimate !== 'number' || p.cost_estimate >= 100) return false; // strictly < $100
    return true;
  })
  .map(p => p.id);

// Saved projects that are in the qualifying set
const qualifyingSaved = saved.filter(sp => qualifyingProjectIds.includes(sp.diy_project_id));

// CP1-3 (≈0.3333 each): At least 1,2,3 qualifying DIY projects saved
[1, 2, 3].forEach(n => {
  checkpoints.push({
    passed: qualifyingSaved.length >= n,
    weight: 1.0 / 3.0
  });
});

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
